// Keeps ONLY the columns the AI needs to save API token costs
return $input.all().map(item => {
    return {
        json: {
            // CRITICAL: We must keep the row_id so we can merge it later!
            row_id: item.json.row_id,
            Raw_Model: item.json.Raw_Model || "NotFound",
